    for (char c : s) {
        int digit = c - '0';
        if (digit < 1 || digit > 9) return false;
        count[digit]++;
    }
    for (int k = 1; k <= 9; ++k) {
        if (count[k] != 0 && count[k] != k) {
            return false;
        }
    }
    return true;
}

long long solve(long long n) {
    long long current = n + 1;
    while (true) {
        if (isSpecial(current)) {
            return current;
        }
        current++;
        // To prevent infinite loop in case of very large n (though constraints say n <= 1e15)
        if (current > LLONG_MAX - 1) {
            return -1; // indicates no solution found (though problem says there is one)
        }
    }
